mapper.select:
select 
from exam_record er
left join exam e on er.exam_id = e.id
left join paper p on er.paper_id = p.id
left join candidate c on er.candidate_id = c.id


        and er.exam_id = #{examId}


        and er.candidate_id = #{candidateId}


        and er.status = #{status}


        and p.department_id = #{departmentId}


        and COALESCE(er.exam_name, e.name) like concat('%', #{examName}, '%')


        and COALESCE(er.candidate_name, c.name) like concat('%', #{candidateName}, '%')


order by er.create_time desc

mapper.update:
update exam_record
submit_time = #{submitTime}, total_score = #{totalScore}, objective_score = #{objectiveScore}, subjective_score = #{subjectiveScore}, status = #{status},
where id = #{id}
